sp_widget.client_script:
api.controller = function() {
    var c = this;
    c.loading = false;
};

sp_widget.css:
.sp-card-grid {
    display: flex;
    flex-wrap: wrap;
}
.sp-card-grid > [class*="col-"] {
    display: flex;
    margin-bottom: 24px;
}
.sp-card {
    display: flex;
    flex-direction: column;
    width: 100%;
    border: 1px solid $border-tertiary;
    border-radius: $border-radius-large;
    box-shadow: 0 1px 4px rgba($text-color, 0.07);
    background: $background-primary;
    overflow: hidden;
    margin-bottom: 0;
}
.sp-card-header {
    padding: 16px 24px;
    background: $background-primary;
    border-bottom: 1px solid $border-tertiary;
    min-height: 52px;
    flex-shrink: 0;
}
.sp-card-title {
    font-size: $font-size-large;
    font-weight: 600;
    color: $text-color;
    margin: 0;
}
.sp-card-body {
    padding: 24px;
    flex: 1 1 auto;
    display: flex;
    flex-direction: column;
}
.sp-card-content {
    flex: 1 1 auto;
}
.sp-card-content p {
    margin-bottom: 8px;
    color: $text-secondary;
    font-size: $font-size-base;
}
.sp-card-content .glyphicon {
    margin-right: 8px;
    color: $brand-primary;
    font-size: 14px;
}
.sp-card-bottom {
    margin-top: auto;
    padding-top: 16px;
}
.sp-btn-primary {
    height: 44px;
    padding: 0 20px;
    border-radius: $border-radius-base;
    font-size: $font-size-base;
    font-weight: 500;
    display: inline-flex;
    align-items: center;
    gap: 8px;
    transition: background 0.15s, box-shadow 0.15s;
    cursor: pointer;
    border: none;
    background: $brand-primary;
    color: $btn-primary-color;
    &:hover:not(:disabled) {
        background: $brand-primary-dark;
        box-shadow: 0 2px 8px rgba($brand-primary, 0.3);
        color: $btn-primary-color;
    }
}
.sp-empty-state {
    padding: 64px 24px;
}
.sp-empty-icon {
    font-size: 48px;
    margin-bottom: 16px;
    display: block;
    opacity: 0.35;
    color: $text-muted;
}
.sp-empty-title {
    font-size: $font-size-large;
    font-weight: 600;
    color: $text-color;
    margin-bottom: 8px;
}

sp_widget.script:
(function() {
    data.events = [];
    data.message = '';

    try {
        if (input && input.action === 'refresh') {
            // Same logic as initial load — allows client refresh
        }

        var userId = gs.getUserID();
        var userGr = new GlideRecord('sys_user');
        var userCollege = '';
        if (userGr.get(userId)) {
            userCollege = userGr.getValue('u_college') + '';
        }

        var today = new GlideDateTime().getLocalDate().toString();

        var gr = new GlideRecord('x_2097092_linq_event');
        gr.addQuery('status', 'live');
        gr.addQuery('event_date', '>=', today);
        gr.orderBy('event_date');
        gr.setLimit(50);
        gr.query();

        while (gr.next()) {
            var scope = gr.getValue('scope') + '';
            var eventCollege = gr.getValue('college') + '';

            // Filter: college_only events show only if user belongs to that college
            if (scope === 'college_only' && eventCollege !== userCollege) {
                continue;
            }

            data.events.push({
                sys_id: gr.getUniqueValue(),
                title: gr.getValue('title') + '',
                club_name: gr.getDisplayValue('club') + '',
                event_date: gr.getDisplayValue('event_date') + '',
                venue: gr.getValue('venue') + '',
                scope: scope
            });
        }
    } catch (e) {
        gs.error('linq-event-listing error: ' + e.message);
        data.message = 'An error occurred loading events.';
    }
})();
